import { useEffect, useState } from "react"
import "./moviesstyle.css"
function Movies() {
    let [allmovies, changeallmovies] = useState()
    useEffect(() => {
        async function getmovies() {
            let movieslist = []
            for(let i = 1; i <= 5; i++) {
                let fetchmov = await fetch(`https://api.themoviedb.org/3/movie/popular?api_key=438b5d80663af506dbe9658849a35777&language=en-US&page=${i}`)
                let jsonfetchmov = await fetchmov.json()
                let res = jsonfetchmov.results.map((item) => {
                    return <div id={`movie-card-${item.id}`}>
                        <img id={`movie-img-${item.id}`} src={`https://image.tmdb.org/t/p/w500${item.backdrop_path}`}/>
                        <p id={`movie-title-${item.id}`}>{item.original_title}</p>
                        <p id={`movie-pop-${item.id}`}>{item.popularity}</p>
                        <p id={`movie-vote-${item.id}`}>{item.vote_average}</p>
                        <p id={`movie-date-${item.id}`}>{item.release_date}</p> 
                    </div>
                })//add svg's to each <p>
               changeallmovies(res)
            }
            
        }
        getmovies()
    }, [])
    return<>
        <div id="movies-shell">
            <div id="movies-header">
                <p id="movies-title">Popular Movies</p>
               
            </div>

            <div id="movies-row">
                {allmovies}
            </div>
        </div>
    </>
}
export default Movies
